            //
            aOrbiterC = ((aOrbiterC + aOrbiterE) + 0x6FCBAB81F29E9506ULL) + aOrbiterUpdateSaltD[(((31U - aIndex) + 5U)) & 31];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 0x0B8A79EDA07CCB86ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x15D1C0A170EC9D5DULL), 19U);
            //
