            aOrbiterH = ((aWandererJ + RotL64(aPrevious, 5U)) + 0x22A6DB2E59C70F5CULL) + aNonceWordF;
            aOrbiterG = (((aWandererE + RotL64(aIngress, 3U)) + RotL64(aCarry, 3U)) + 0x578EBE9E7B0D0249ULL) + aNonceWordE;
            aOrbiterK = ((aWandererB + RotL64(aScatter, 23U)) + 0x6DD488B4D2E43AC2ULL) + aNonceWordH;
