            aIngress = aOrbiterB ^ RotL64(aOrbiterF, 44U);
            aIngress = aIngress + (RotL64(aOrbiterA, 53U) ^ aOrbiterH);
            aIngress = aIngress + (RotL64(aOrbiterK, 27U) ^ aOrbiterD);
