            aCross = (RotL64(aWorkLaneC[((S_BLOCK1 - aIndex + 2747U)) & S_BLOCK1], 43U) ^ RotL64(aWorkLaneD[((S_BLOCK1 - aIndex + 1977U)) & S_BLOCK1], 23U));
